// left[node] == -1 means leaf node
func eval(node int, f []float64) float64 {
	for {
		if left[node] < 0 {
			return value[node]
		}
		v := f[feature[node]]
		switch {
		case math.IsNaN(v):
			node = missing[node]
		case float32(v) < threshold[node]:
			node = left[node]
		default:
			node = right[node]
		}
	}
}

// PredictScores returns raw per-class scores.
func PredictScores(f []float64) []float64 {
	s := make([]float64, numClasses)
	copy(s, classBase)
	for c := 0; c < numClasses; c++ {
		for i := 0; i < treesPerClass; i++ {
			s[c] += eval(roots[c+i*numClasses], f)
		}
	}
	return s
}

// Predict returns softmax probabilities over all classes.
func Predict(f []float64) []float64 {
	s := PredictScores(f)
	max := s[0]
	for _, v := range s {
		if v > max {
			max = v
		}
	}
	sum := 0.0
	for i := range s {
		s[i] = math.Exp(s[i] - max)
		sum += s[i]
	}
	for i := range s {
		s[i] /= sum
	}
	return s
}

// PredictClass returns the class index with the highest probability.
func PredictClass(f []float64) int {
	p := PredictScores(f)
	best := 0
	for i := range p {
		if p[i] > p[best] {
			best = i
		}
	}
	return best
}
